INSERT IGNORE INTO `shop_storages_interfaces_types` VALUES (1,1,'2 My warehouse (for my own catalog)','Used for the built-in product catalog (the catalog with product categories). Availability and prices can be specified through the \"Stock management\" page, accessible from the control panel. In order for you to be able to edit prices and availability for this warehouse - specify yourself as a warehouseman in the settings below.','[]','',1),(2,2,'1 Simple price list','Used for regular price lists to search for products by part number. You can create and update the price lists through the \"Price List Manager\", accessible from the control panel. In the connection settings (below), select the price list you created earlier through the \"Price List Manager\".','[{\"caption\":\"Price list\",\"name\":\"price_id\",\"type\":\"select\",\"options_way\":\"sql\",\"options\": \"SELECT `id` AS `value`, `name` AS `caption` FROM `shop_docpart_prices`;\"},{\"name\":\"probability\",\"type\":\"text\",\"caption\":\"Delivery probability, %\"},{\"name\":\"color\",\"type\":\"color\",\"caption\":\"Color\"}]','prices',1),(3,2,'Веб-сервис ABCP','','[{\"name\":\"login\",\"type\":\"text\",\"caption\":\"Логин\"},{\"name\":\"password\",\"type\":\"text\",\"caption\":\"Пароль\"},{\"name\":\"color\",\"type\":\"color\",\"caption\":\"Цвет\"},{\"name\":\"probability\",\"type\":\"text\",\"caption\":\"Вероятность поставки, %\"},{\"name\":\"subdomain\",\"type\":\"text\",\"caption\":\"Поддомен из URL вида поддомен.public.api.abcp.ru (URL уточните у поставщика). Указать ТОЛЬКО поддомен, т.е. БЕЗ http://, БЕЗ https:// и БЕЗ .public.api.abcp.ru\"}]','abcp',0),(4,2,'Веб-сервис Автопитер','','[{\"name\":\"user\",\"type\":\"text\",\"caption\":\"Логин\"},{\"name\":\"password\",\"type\":\"text\",\"caption\":\"Пароль\"},{\"name\":\"color\",\"type\":\"color\",\"caption\":\"Цвет\"}]','autopiter',0),(5,2,'Веб-сервис ABS-Auto','','[{\"name\":\"user\",\"type\":\"text\",\"caption\":\"Логин\"},{\"name\":\"password\",\